import { getRun, setRunStatus, findUnfinishedStep, setStepStatus } from '../store/runs';

// Returns true only when the run was actually flipped back to running. Every precondition miss
// resolves to FALSE (not a throw): missing run, non-reopenable status, no unfinished step.
export async function reopenFailedRun(runId: string, driverJobId: string): Promise<boolean> {
  const run = await getRun(runId);
  if (!run) return false;
  if (run.status !== 'failed' && run.status !== 'paused') return false;
  const step = await findUnfinishedStep(runId);
  if (!step) return false;
  await setStepStatus(step.id, 'running', { completedAt: null });
  await setRunStatus(runId, 'running');
  return true;
}

