import type { Job } from '../store/jobs';
import { reopenFailedRun } from '../runs/reopen';
import { startWorkerStream } from './stream';

// Claim path: a worker picked up a job. A RETRIED job continues in the same run, so its run/step
// must be un-failed before the worker's next "done" is accepted (a terminal run discards it).
export async function handleClaimedJob(job: Job): Promise<void> {
  if (job.isRetry && job.runId) {
    try {
      await reopenFailedRun(job.runId, job.id);
    } catch (err) {
      console.warn('[claim] reopenFailedRun threw', { jobId: job.id, err });
    }
  }
  await startWorkerStream(job);
}

