import { getJob, updateJob } from '../store/jobs';

// A job started in "wait" mode is parked until an external event; the poller deliberately skips
// those rows. Retry re-queues a failed job so the poller re-claims it.
export async function retryJob(jobId: string): Promise<void> {
  const job = await getJob(jobId);
  if (!job || job.status !== 'failed') return;
  await updateJob(jobId, { status: 'queued', result: {} });
}

