// A restart-interrupted run is cancelled + carries a RESTART_INTERRUPTION marker. Only THAT kind of
// cancel is revivable; a plain user cancel is final.
export async function resumeInterruptedRun(runId: string): Promise<boolean> {
  const run = await getRun(runId);
  if (run?.status !== 'cancelled') return false;
  if (!hasRestartMarker(run)) return false;
  const step = await findUnfinishedStep(runId);
  if (!step) return false;
  await setStepStatus(step.id, 'running', { completedAt: null });
  await setRunStatus(runId, 'running');
  return true;
}

