export interface Item { id: string; status: 'pending' | 'pass' | 'fail'; issues: string[]; }
export interface Checklist { items: Item[]; }

export function markItem(list: Checklist, id: string, pass: boolean, failReason?: string): void {
  const item = list.items.find((i) => i.id === id);
  if (!item) return;
  item.status = pass ? 'pass' : 'fail';
  if (pass) item.issues = [];
  if (!pass && failReason) item.issues.push(failReason);
}

export function finalize(list: Checklist): boolean {
  return list.items.every((i) => i.status === 'pass' && i.issues.length === 0);
}

