import { reopenShard } from '../store/shards';
import { retryJobCas } from '../store/jobs';

// Retry one shard member. The shard bookkeeping must reflect an in-flight member so a later terminal
// event finalizes the stage correctly.
export async function carryOnShardMember(shardId: string, jobId: string): Promise<{ ok: boolean }> {
  const flipped = await retryJobCas(jobId, ['failed'], 'running');
  if (!flipped) return { ok: false };
  await reopenShard(shardId, 'running');
  return { ok: true };
}

