import { readSourceToken, markRowNeedsReauth } from '../store/auth';

const EXPIRY_SKEW_MS = 5000;

export interface CredRow { id: string; needsReauthAt: number | null; }
export interface CredResult { token: string | null; }

export async function rowToCredential(row: CredRow): Promise<CredResult> {
  // A previously flagged row is done: the user must reconnect.
  if (row.needsReauthAt != null) return { token: null };

  const src = await readSourceToken(row.id);
  if (!src) return { token: null };
  if (src.expiresAt != null && src.expiresAt <= Date.now() + EXPIRY_SKEW_MS) {
    // Near expiry — the CLI owns rotation and may refresh momentarily. Fall through empty; the
    // NEXT read re-reads the source and picks up a rotated token.
    return { token: null };
  }
  return { token: src.token };
}

