import { db } from '../store/db';

// CAS helper: flips a step to newStatus ONLY if it is currently one of expect. Returns rows changed.
export async function setStepStatusIf(
  stepId: string, expect: string[], newStatus: string, patch: Record<string, unknown> = {},
): Promise<number> {
  const res = await db.update('steps', { status: newStatus, ...patch }, { id: stepId, statusIn: expect });
  return res.rowCount;
}

export async function unparkStep(stepId: string): Promise<number> {
  // Only a still-paused step should be reopened; a concurrently advanced step must not be touched.
  return setStepStatusIf(stepId, ['paused'], 'running', { output: null, completedAt: null });
}

