const APPLICABLE = ['running', 'queued'];

// Apply an agent lifecycle signal to the linked job — but never over a newer terminal state.
export async function persistSignal(jobId: string, nextStatus: string): Promise<boolean> {
  // Conditional write: only applies if the row is STILL in an applicable status. One statement,
