import { mkdirSync, rmSync } from 'node:fs';

const LOCK_WAIT_MS = 5000;

// Cross-process lock via atomic mkdir. Runs fn() only while the lock is held; releases on exit.
export function withLock<T>(lockDir: string, fn: () => T): T {
  const deadline = Date.now() + LOCK_WAIT_MS;
  let held = false;
  while (Date.now() <= deadline) {
    try { mkdirSync(lockDir); held = true; break; } catch { /* contended */ }
  }
  if (!held) throw new Error('timed out acquiring lock: ' + lockDir);
  try { return fn(); } finally { rmSync(lockDir, { recursive: true, force: true }); }
}

