import { getQueue, enqueueAndSend } from './queue';

// Handles a chat-ready broadcast in ONE tab. isOwner is true only in the tab that owns this subJob,
// so a retry dispatches exactly once even though every tab receives the event.
export function onChatReady(data: { subJobId: string; prompt: string; isRetry: boolean; isOwner: boolean }): void {
  const q = getQueue(data.subJobId);
  const alreadySent = q.sent.includes(data.prompt);
  const alreadyQueued = q.pending.includes(data.prompt);
  if ((alreadySent && !data.isRetry) || alreadyQueued) return;
  if (data.isRetry && !data.isOwner) return; // only the owner tab dispatches the retry
  enqueueAndSend(data.subJobId, data.prompt);
}

