import { getJob, updateJob } from '../store/jobs';

// result can be an object OR a JSON string (cloud-mirrored rows store it as a string).
function parseResult(result: unknown): Record<string, unknown> {
  if (typeof result === 'string') {
    try { const p = JSON.parse(result); return p && typeof p === 'object' ? p as Record<string, unknown> : {}; }
    catch { return {}; }
  }
  return result && typeof result === 'object' ? result as Record<string, unknown> : {};
}

export async function resolveTransition(jobId: string, signal: { status: string }): Promise<void> {
  const job = await getJob(jobId);
  const prior = parseResult(job.result);
  const nextResult = { ...prior, lastSignal: signal.status };
  await updateJob(jobId, { status: signal.status, result: nextResult });
}

