export interface Link { chatId: string; groupId: string; createdAt: number; }

// chatId -> groupId for the chat's NEWEST group. Sort so a chat linked to several groups resolves
// deterministically instead of last-row-wins on an unordered scan.
export function buildGroupMap(links: Link[]): Map<string, string> {
  const m = new Map<string, string>();
  const byNewest = [...links].sort((a, b) => a.createdAt - b.createdAt);
  for (const l of byNewest) m.set(l.chatId, l.groupId); // later (newer) wins
  return m;
}

