// A stray "completed" from an agent is downgraded to the reviewable "done" status.
function coerceStatus(state: string): string {
  return state === 'completed' ? 'done' : state;
}

export async function resolveTransition(jobId: string, signal: { state: string }): Promise<void> {
  const status = coerceStatus(signal.state);
  const persistedSignal = { ...signal, state: status };
  await updateJob(jobId, { status, result: { lastSignal: persistedSignal } });
}

