import { readFileSync } from 'node:fs';

export interface Manifest { version: 1; branches: Record<string, unknown>; }

export function readManifest(file: string): Manifest {
  try {
    const m = JSON.parse(readFileSync(file, 'utf8'));
    if (m && m.version === 1 && m.branches && typeof m.branches === 'object') return m;
    if (m && typeof m.version === 'number') {
      // A newer/unknown schema is NOT ours to reset — refuse rather than erase it.
      throw new Error('unsupported manifest version ' + m.version);
    }
  } catch (e) {
    if ((e as { code?: string }).code !== 'ENOENT' && !(e instanceof SyntaxError)) throw e;
  }
  return { version: 1, branches: {} };
}

