import { z } from 'zod';

const questionSchema = z.object({ prompt: z.string().min(1), options: z.array(z.string()).min(1) });

const argsSchema = z.object({
  state: z.enum(['done', 'failed', 'awaiting_input']),
  summary: z.string().min(1),
  // Loose at the top level so a stray value on a terminal state cannot fail the whole signal.
  questions: z.unknown().optional(),
});

export function parseSignal(input: unknown): { state: string; questions?: unknown[] } | null {
  const parsed = argsSchema.safeParse(input);
  if (!parsed.success) return null;
  let questions: unknown[] | undefined;
  if (parsed.data.state === 'awaiting_input' && parsed.data.questions !== undefined) {
    const v = z.array(questionSchema).max(10).safeParse(parsed.data.questions);
    if (v.success && v.data.length > 0) questions = v.data;
  }
  return { state: parsed.data.state, questions };
}

