// Extract the working directory a git command targets. Only a GIT-LEVEL "-C <dir>" (before the
// subcommand) overrides cwd; a "-C" appearing after the subcommand (e.g. "commit -C <commit>") is a
// subcommand flag and must be ignored.
const GIT_LEVEL_C = /\bgit\s+(?:-c\s+\S+\s+)*-C\s+("[^"]*"|'[^']*'|\S+)\s+(?:commit|merge|rebase)\b/;

export function extractTargetDir(cmd: string, cwd: string): string {
  const m = cmd.match(GIT_LEVEL_C);
  if (!m) return cwd;
  return m[1].replace(/^["']|["']$/g, '');
}

