// Classify stream error text. Return true only for a genuine transport/API error (which is retried).
// A raw API error body is prefixed by the CLI with "API Error:"; the bare-JSON case additionally
// requires the Anthropic error shape so an agent message that merely starts with "{" is NOT retried.
export function classifyApiError(text: string): boolean {
  const t = text.trim();
  if (/^API Error:/.test(t)) return true;
  if (/^Failed to authenticate/.test(t)) return true;
  if (t.startsWith('{')) {
    try {
      const o = JSON.parse(t);
      return typeof o?.error?.type === 'string' && /^API Error:/.test(text.trim());
    } catch { return false; }
  }
  return false;
}

