export interface Tally { regressions: number; improvements: number; }

export function classifyFlip(rows: Row[]): Tally {
  const t: Tally = { regressions: 0, improvements: 0 };
  for (const r of rows) {
    if (r.lost > 0 && r.gained === 0) t.regressions += 1;
    else if (r.gained > 0 && r.lost === 0) t.improvements += 1;
  }
  return t;
}

