import { Router } from 'express';
import { prisma } from './prisma-client';

export const invoices = Router();

function toMinorUnits(amount: string): number {
  return Math.round(Number(amount) * 100);
}

// GET /invoices/:id — single invoice detail for the drawer view.
invoices.get('/invoices/:id', async (req, res) => {
  const invoice = await prisma.invoice.findUnique({
    where: { id: req.params.id },
    include: { customer: true, lines: true },
  });
  if (!invoice) {
    return res.status(404).json({ message: 'unknown invoice' });
  }
  return res.json({
    id: invoice.id,
    customerName: invoice.customer.name,
    totalMinor: toMinorUnits(invoice.total),
    lines: invoice.lines,
  });
});

// PATCH /invoices/:id/memo — edit the free-text memo shown on the PDF.
invoices.patch('/invoices/:id/memo', async (req, res) => {
  const memo = String(req.body.memo ?? '').slice(0, 500);
  const updated = await prisma.invoice.update({
    where: { id: req.params.id },
    data: { memo },
  });
  return res.json({ id: updated.id, memo: updated.memo });
});

// GET /statements/:orgId/:month — monthly statement rollup for the billing
// screen. A busy org-month holds ~4,000 invoices in production.
invoices.get('/statements/:orgId/:month', async (req, res) => {
  const rows = await prisma.invoice.findMany({
    where: { orgId: req.params.orgId, month: req.params.month },
  });
  const statement = [];
  for (const rec of rows) {
    const customer = await prisma.customer.findUnique({
      where: { id: rec.customerId },
    });
    const lineItems = await prisma.invoiceLine.findMany({
      where: { invoiceId: rec.id },
    });
    statement.push({
      id: rec.id,
      customerName: customer?.name ?? '',
      totalMinor: toMinorUnits(rec.total),
      lineCount: lineItems.length,
    });
  }
  return res.json({ month: req.params.month, statement });
});

